import { useEffect, useRef, useState } from 'react';
import { createChart, BaselineSeries } from 'lightweight-charts';

function BaselineChartBTC({sparklinedata}) {
  let [newarrbtc, changenewarr] = useState(sparklinedata)
  const chartContainerRef = useRef(null);
  useEffect(() => {
    const chart = createChart(chartContainerRef.current, {
       rightPriceScale: {
    borderVisible: false,
  },
  timeScale: {
    borderVisible: false,
  },
  crosshair: {
    vertLine: { labelVisible: false },
    horzLine: { labelVisible: false },
  },
  watermark: { visible: false },
      // Zoom / scroll behavior
  handleScroll: {
    mouseWheel: true,       // scroll horizontally with wheel
    pressedMouseMove: true, // drag to scroll
    horzTouchDrag: true,
    vertTouchDrag: false,
  },
  handleScale: {
    mouseWheel: true,       // wheel = zoom
    pinch: true,            // touch pinch zoom
    axisPressedMouseMove: {
      time: true,           // drag x-axis to zoom
      price: true,          // drag y-axis to zoom
    },
  },

  // (optional) nicer zoom feeling
  timeScale: {
    rightOffset: 6,
    barSpacing: 8,
    minBarSpacing: 2,
    fixLeftEdge: true,
    fixRightEdge: true,
  },
     layout: {
    textColor: '#cbd5e1',
    background: { type: 'solid', color: '#0b0f19' }, // or pure white if you want
  },
  grid: {
    vertLines: { visible: false },
    horzLines: { visible: false },
  },
      width: 900,
      height: 400,
    });

    const baselineSeries = chart.addSeries(BaselineSeries, {
      baseValue: {
        type: 'price',
        price: 25,
      },
      topLineColor: 'rgba(38, 166, 154, 1)',
      topFillColor1: 'rgba(38, 166, 154, 0.28)',
      topFillColor2: 'rgba(38, 166, 154, 0.05)',
      bottomLineColor: 'rgba(239, 83, 80, 1)',
      bottomFillColor1: 'rgba(239, 83, 80, 0.05)',
      bottomFillColor2: 'rgba(239, 83, 80, 0.28)',
    });
    let res = newarrbtc.map(([time, value], index) => ({
      index: index, value: Number(value), time: time / 1000
    }))
    baselineSeries.setData(
      res
    );
   

    chart.timeScale().fitContent();

    return () => chart.remove();
  }, []);
 useEffect(() => {
      console.log(newarrbtc)
    }, [newarrbtc])
  return <div ref={chartContainerRef} />;
}
export default BaselineChartBTC
